// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

contract EventDemo {
    event Transfer(address indexed from, address indexed to, uint256 value);
    event DataUpdate(address indexed user, uint256 indexed id, string data, uint256 timestamp);

    mapping(address => uint256) public balances;

    constructor() {
        balances[msg.sender] = 1000;
    }

    function transfer(address to, uint256 amount) public {
        require(balances[msg.sender] >= amount, "Insufficient balance");

        balances[msg.sender] -= amount;
        balances[to] += amount;

        emit Transfer(msg.sender, to, amount);
    }

    function updateData(uint256 id, string memory data) public {
        emit DataUpdate(msg.sender, id, data, block.timestamp);
    }
}

contracts/MyToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

contract MyToken {
    // 1. 代币基本信息
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;

    // 2. 状态变量
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    // 3. 所有者（用于权限控制）
    address public owner;

    // 4. 事件
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    // 5. 修饰符
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this");
        _;
    }

    // 6. 构造函数
    constructor(
        string memory _name,
        string memory _symbol,
        uint8 _decimals,
        uint256 _initialSupply
    ) {
        name = _name;
        symbol = _symbol;
        decimals = _decimals;
        totalSupply = _initialSupply * 10**_decimals;
        owner = msg.sender;
        balanceOf[msg.sender] = totalSupply;
        emit Transfer(address(0), msg.sender, totalSupply);
    }

    // 7. 核心函数（见下文）
    function transfer(address to, uint256 amount) public returns (bool) {
        // 1. 检查接收地址
        require(to != address(0), "Cannot transfer to zero address");

        // 2. 检查余额
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");

        // 3. 更新余额
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;

        // 4. 触发事件
        emit Transfer(msg.sender, to, amount);

        // 5. 返回成功
        return true;
    }
    function approve(address spender, uint256 amount) public returns (bool) {
        // 1. 检查被授权人地址
        require(spender != address(0), "Cannot approve zero address");

        // 2. 设置授权额度
        allowance[msg.sender][spender] = amount;

        // 3. 触发事件
        emit Approval(msg.sender, spender, amount);

        // 4. 返回成功
        return true;
    }
    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) public returns (bool) {
        // 1. 检查地址有效性
        require(from != address(0), "From zero");
        require(to != address(0), "To zero");

        // 2. 检查余额
        require(balanceOf[from] >= amount, "Insufficient balance");

        // 3. 检查授权额度
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");

        // 4. 执行转账
        balanceOf[from] -= amount;
        balanceOf[to] += amount;

        // 5. 减少授权额度
        allowance[from][msg.sender] -= amount;

        // 6. 触发事件
        emit Transfer(from, to, amount);

        // 7. 返回成功
        return true;
    }
}
